    /**
     * Create an inline derived table from this table
     */
    override fun whereExists(select: Select<*>): Events = where(DSL.exists(select))

    /**
     * Create an inline derived table from this table
     */
    override fun whereNotExists(select: Select<*>): Events = where(DSL.notExists(select))
}
